mapper.insert:
/* 챗 가이드 인사멘트 등록/수정 */
INSERT INTO TB_CHAT_GUIDE (
    GUIDE_ID
    , GUIDE_TP_CD
    , GUIDE_KEY
    , ENBL_YN
    , CONTENT
    , MODIFY_DT
) VALUES (
    #{guideId}
    , '001'
    , #{guideKey}
    , #{enblYn}
    , #{content}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    GUIDE_TP_CD = '001'
    , GUIDE_KEY = VALUES(GUIDE_KEY)
    , ENBL_YN = VALUES(ENBL_YN)
    , CONTENT = VALUES(CONTENT)
    , MODIFY_DT = NOW()

/* 챗 가이드 안내멘트 등록/수정 */
INSERT INTO TB_CHAT_GUIDE (
    GUIDE_ID
    , GUIDE_TP_CD
    , GUIDE_KEY
    , ENBL_YN
    , CONTENT
    , DSPL_COND
    , MODIFY_DT
) VALUES (
    #{guideId}
    , '002'
    , #{guideKey}
    , #{enblYn}
    , #{content}
    , #{dsplCond}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    GUIDE_TP_CD = '002'
    , GUIDE_KEY = VALUES(GUIDE_KEY)
    , ENBL_YN = VALUES(ENBL_YN)
    , CONTENT = VALUES(CONTENT)
    , DSPL_COND = VALUES(DSPL_COND)
    , MODIFY_DT = NOW()

/* 챗 가이드 오류메시지 등록/수정 */
INSERT INTO TB_CHAT_GUIDE (
    GUIDE_ID
    , GUIDE_TP_CD
    , GUIDE_KEY
    , ENBL_YN
    , CONTENT
    , MAX_CHARS
    , MODIFY_DT
) VALUES (
    #{guideId}
    , '003'
    , #{guideKey}
    , #{enblYn}
    , #{content}
    , #{maxChars}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    GUIDE_TP_CD = '003'
    , GUIDE_KEY = VALUES(GUIDE_KEY)
    , ENBL_YN = VALUES(ENBL_YN)
    , CONTENT = VALUES(CONTENT)
    , MAX_CHARS = VALUES(MAX_CHARS)
    , MODIFY_DT = NOW()

/* 챗 가이드 점검/장애 등록/수정 */
INSERT INTO TB_CHAT_GUIDE (
    GUIDE_ID
    , GUIDE_TP_CD
    , GUIDE_KEY
    , ENBL_YN
    , CONTENT
    , START_DT
    , END_DT
    , MODIFY_DT
) VALUES (
    #{guideId}
    , '004'
    , #{guideKey}
    , #{enblYn}
    , #{content}
    , #{startDt}
    , #{endDt}
    , NOW()
)
ON DUPLICATE KEY UPDATE
    GUIDE_TP_CD = '004'
    , GUIDE_KEY = VALUES(GUIDE_KEY)
    , ENBL_YN = VALUES(ENBL_YN)
    , CONTENT = VALUES(CONTENT)
    , START_DT = VALUES(START_DT)
    , END_DT = VALUES(END_DT)
    , MODIFY_DT = NOW()
